class Solution {
    public List<Integer> powerfulIntegers(int x, int y, int bound) {
        Set<Integer> xPowers = new HashSet<>();
        {
            long current = 1;
            xPowers.add((int) current);
            if (x != 1) {
                while (true) {
                    long next = current * x;
                    if (next > bound - 1) {
                        break;
                    }
                    current = next;
                    xPowers.add((int) current);
                }
            }
        }

        Set<Integer> yPowers = new HashSet<>();
        {
            long current = 1;
            yPowers.add((int) current);
            if (y != 1) {
                while (true) {
                    long next = current * y;
                    if (next > bound - 1) {
                        break;
                    }
                    current = next;
                    yPowers.add((int) current);
                }
            }
        }

        Set<Integer> result = new HashSet<>();
        for (int a : xPowers) {
            for (int b : yPowers) {
                int sum = a + b;
                if (sum <= bound) {
                    result.add(sum);
                }
            }
        }

        return new ArrayList<>(result);
    }
}

